definition.customCSS:
.[$FRAGMENT_CLASS$] .management-bar-wrapper {
background-color: var(--white);
}

.[$FRAGMENT_CLASS$] .container {
max-width: none;
padding-left: 1.5rem;
padding-right: 1.5rem;
}

.[$FRAGMENT_CLASS$] .portlet-content {
position: relative;
}

.[$FRAGMENT_CLASS$] .commerce-header {
margin-bottom: 2.5rem;
}

.[$FRAGMENT_CLASS$] .commerce-header .container-fluid-max-xxxl {
padding-left: 1.5rem;
padding-right: 1.5rem;
}

.[$FRAGMENT_CLASS$] .portlet-header {
left: 0;
padding-left: 1.5rem;
position: absolute;
top: 4.5rem;
}
